class Solution:
    def maxProfit(self, prices):
        best = 0
        for i in range(len(prices)):
            for j in range(i + 1, len(prices)):
                if prices[j] - prices[i] > best:
                    best = prices[j] - prices[i]
        return best

solutions.python:
class Solution:
    def maxProfit(self, prices):
        lo = float('inf')
        best = 0
        for p in prices:
            if p < lo:
                lo = p
            elif p - lo > best:
                best = p - lo
        return best

